+            ([Description("The search query to look up on the web")] string query) =>
+            {
+                var logger = loggerFactory.CreateLogger("WebSearch");
+                logger.LogInformation("Searching: {Query}", query);
+                return WebSearchTool.SearchAsync(query);
+            },
+            "web_search",
+            "Searches the web for information on a given query and returns relevant snippets."),
+
+        AIFunctionFactory.Create(
+            ([Description("Title or label for the note")] string title,
+             [Description("Content of the note to save")] string content) =>
+            {
+                var logger = loggerFactory.CreateLogger("Notes");
+                logger.LogInformation("Saving note: {Title}", title);
+                noteService.AddNote(title, content);
+                return $"Note '{title}' saved successfully.";
+            },
+            "save_note",
+            "Saves a research note with a title and content for later reference."),
+
+        AIFunctionFactory.Create(
+            () => noteService.GetAllNotes(),
+            "get_notes",
+            "Retrieves all previously saved research notes."),
+    };
+
+    return new ChatClientAgent(
+        chatClient,
+        instructions: """
+            You are a research assistant. When given a topic:
+            1. Search the web multiple times to gather diverse information.
+            2. Save important findings as notes using the save_note tool.
+            3. After gathering enough information, retrieve your notes and write
+               a comprehensive summary with key findings, organized by theme.
+            Always cite your sources. Be thorough but concise.
+            """,
+        name: "ResearchAgent",
+        description: "An agent that researches topics by searching the web and taking notes.",
+        tools: tools,
+        loggerFactory: loggerFactory);
+});
+
+using var host = builder.Build();
+
+var agent = host.Services.GetRequiredService<ChatClientAgent>();
+var noteService = host.Services.GetRequiredService<NoteService>();
+var logger = host.Services.GetRequiredService<ILoggerFactory>().CreateLogger("Program");
+
+Console.WriteLine("╔══════════════════════════════════════╗");
+Console.WriteLine("║       AI Research Agent               ║");
+Console.WriteLine("║  Type a topic to research, or 'quit' ║");
+Console.WriteLine("╚══════════════════════════════════════╝");
+Console.WriteLine();
+
+while (true)
+{
+    Console.Write("Research topic> ");
+    var topic = Console.ReadLine()?.Trim();
+    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
+        break;
+
+    noteService.Clear();
+    Console.WriteLine($"\nResearching: {topic}\n");
+
+    try
+    {
+        var response = await agent.RunAsync(
+            $"Research the following topic thoroughly: {topic}",
+            options: new ChatClientAgentRunOptions(new ChatOptions
+            {
+                Temperature = 0f,
+                MaxOutputTokens = 4096,
+            }));
+
+        Console.WriteLine("── Research Summary ──────────────────");
+        Console.WriteLine(response.Text);
+        Console.WriteLine("──────────────────────────────────────\n");
+    }
+    catch (Exception ex)
+    {
+        logger.LogError(ex, "Research failed");
+        Console.WriteLine($"Error: {ex.Message}\n");
+    }
+}

